VALUES
  ('social-worker-moex-02486', 'social-worker', 'social-worker-moex-104-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '下列關於老人福利法的敘述，何者錯誤？', '["立法宗旨目標是維護老人之權益，保障其平等參與社會、政治、經濟、文化等之機會", "勞工主管機構負責主管老人就業免於歧視及支援員工照顧老人家屬與照顧服務員技能檢定之規劃、推 動及監督等事項", "各級政府老人福利之經費來源包括按年編列之老人福利預算、社會福利基金、私人或團體捐贈及其他 收入", "提供原住民老人服務及照顧者，應優先遴用原住民或熟諳原住民文化之人"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "d9e660d04e95", "answer_pdf_sha1": "94a7e373f9b2", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02487', 'social-worker', 'social-worker-moex-104-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '身心障礙者權益保障法中，提供身心障礙者獲得所需之個人支持及照顧，促進其生活品質、社會參與及 自立生活的服務，不包含下列那一項？', '["社區居住", "婚姻及生育輔導", "課後照顧", "緊急救援服務"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "d9e660d04e95", "answer_pdf_sha1": "94a7e373f9b2", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02488', 'social-worker', 'social-worker-moex-104-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '下列何者不是我國長期照顧十年計畫的服務對象？', '["65歲老人", "50歲的山地原住民", "55歲的身心障礙者", "僅IADLs（工具性日常生活活動功能）失能且獨居之老人"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "d9e660d04e95", "answer_pdf_sha1": "94a7e373f9b2", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02489', 'social-worker', 'social-worker-moex-104-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '下列關於身心障礙者個人照顧服務的敘述，何者錯誤？', '["友善服務提供到宅關懷，並支持身心障礙者社會參與", "居家復健是由物理治療師、職能治療師或語言治療師對居家需繼續復健之身心障礙者，於其居住處提 供復健治療服務", "生活重建是指由身心障礙同儕，提供心理支持，以重新建構其獨立生活能力，協助其重建生活", "社區居住是以一般社區住宅房舍提供身心障礙者非機構式之居住服務"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "d9e660d04e95", "answer_pdf_sha1": "94a7e373f9b2", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02490', 'social-worker', 'social-worker-moex-104-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '下列關於兒童及少年福利與權益保障法的敘述，何者錯誤？', '["胎兒（包含死產）出生後7日內，接生人應將其出生之相關資料通報衛生主管機關備查", "出養應以國內收養人優先收養為原則", "政府應建立發展遲緩兒童早期通報系統，並提供早期療育服務", "國內大眾交通運輸、文教設施、康樂場所應提供身高100公分以下兒童優惠措施"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "d9e660d04e95", "answer_pdf_sha1": "94a7e373f9b2", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02491', 'social-worker', 'social-worker-moex-104-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '下列關於發展遲緩早期療育的敘述，何者錯誤？', '["屬於兒童及少年福利服務事項", "政府應建立12歲以下兒童發展之評估機制，並依發展遲緩兒童之需要，提供早期療育服務", "疑似發展遲緩兒童之父母或監護人，得申請警政主管機關建立指紋資料", "各類社會福利、教育及醫療機構，發現有類似發展遲緩兒童，應通報直轄市、縣（市）主管機關"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "d9e660d04e95", "answer_pdf_sha1": "94a7e373f9b2", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02492', 'social-worker', 'social-worker-moex-104-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '專業人員潛意識的把案主當作他以前認識的某特定人看待，因而不能察覺到案主的能力或長處，以致無 法給予案主適當的協助。此現象稱為：', '["非理性思考（irrational thinking）", "投射（projection）", "情感轉移（transference）", "情感反轉移（counter-transference）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "d9e660d04e95", "answer_pdf_sha1": "94a7e373f9b2", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02493', 'social-worker', 'social-worker-moex-104-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '下列關於個案工作預估（assessment）的敘述，何者錯誤？', '["用來找出預期發生的事是否真的發生了", "是一個持續的過程", "是案主和工作人員雙向互動的過程", "交互反應關係的預估（transactional assessment）是以生態系統架構來進行"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "d9e660d04e95", "answer_pdf_sha1": "94a7e373f9b2", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02494', 'social-worker', 'social-worker-moex-104-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '下列關於評估（evaluation）的敘述，何者錯誤？', '["指對一種問題和需求評定的過程", "過程性評估關心工作的過程及各階段的工作如何影響最後的結果", "著重在於案主和工作者所共同設定的目標是否達成", "為了有效運作評估系統，需要採用標準化的紀錄格式"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "d9e660d04e95", "answer_pdf_sha1": "94a7e373f9b2", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02495', 'social-worker', 'social-worker-moex-104-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '以圖形呈現個人、家庭與居家生活的概觀，個人的社會系統與外在世界間關係的消長。這是社會個案工 作常用的什麼工具？', '["網絡圖", "生態圖", "家庭結構圖", "生涯關係圖"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "d9e660d04e95", "answer_pdf_sha1": "94a7e373f9b2", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02496', 'social-worker', 'social-worker-moex-104-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '問題解決學派對於社會工作理論的發展，有重大影響。下列關於問題解決學派的敘述，何者錯誤？', '["皮爾曼（Perlman）於1957年出版《社會個案工作：一個問題解決的過程》（Social Casework：A Problem Solving Process）", "問題解決學派提出的4P是指：person, place, professional, process", "人一生都會不斷面對許多問題，因此協助案主解決問題，需要長時間的逐步介入", "工作方法強調界定問題、討論目標與策略、評估執行情形，都需與案主一同討論"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "d9e660d04e95", "answer_pdf_sha1": "94a7e373f9b2", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02497', 'social-worker', 'social-worker-moex-104-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '在瞭解案主所面臨的問題時，重視從案主所在情境中去評量（assess），同時探討案主早期生命經驗與目 前環境中的社會關係。請問這是那一個理論觀點？', '["增強權能觀點", "基變觀點", "心理暨社會學派", "認知行為學派"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "d9e660d04e95", "answer_pdf_sha1": "94a7e373f9b2", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02498', 'social-worker', 'social-worker-moex-104-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '應用系統理論觀點去分析家庭問題，下列敘述何者錯誤？', '["家庭可能在某些時期，屬於開放系統；但是在某些時候，成為封閉系統", "案主童年時期與母親間的依附關係，會影響他現在與孩子之間的關係", "家庭成員間的角色關係會隨著家庭動力與內外在情境因素而變動", "家庭與外界之間，以及家庭成員彼此間的界線（boundary），是基本且重要的"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "d9e660d04e95", "answer_pdf_sha1": "94a7e373f9b2", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
